@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="HandleRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Company"
                       @onchange="e => Update(company: e.Value?.ToString())" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Title"
                       @onchange="e => Update(title: e.Value?.ToString())" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(startDate: DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@IsCurrent"
                       @onchange="e => Update(endDate: DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent"
                           @onchange="e => Update(isCurrent: (bool?)e.Value)" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description"
                          @onchange="e => Update(description: e.Value?.ToString())"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime? StartDate { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private async Task Update(string? company = null, string? title = null,
        DateTime? startDate = null, DateTime? endDate = null,
        bool? isCurrent = null, string? description = null)
    {
        var data = new WorkEntryData(
            company ?? Company,
            title ?? Title,
            startDate ?? StartDate,
            isCurrent ?? IsCurrent ? null : (endDate ?? EndDate),
            isCurrent ?? IsCurrent,
            description ?? Description
        );
        if (isCurrent == true)
        {
            data = data with { EndDate = null };
        }
        await OnChanged.InvokeAsync(data);
    }

    private async Task HandleRemove() => await OnRemove.InvokeAsync();

    public record WorkEntryData(string Company, string Title, DateTime? StartDate, DateTime? EndDate, bool IsCurrent, string Description);
}

@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="HandleRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Name"
                       @onchange="e => Update(name: e.Value?.ToString())" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Relationship"
                       @onchange="e => Update(relationship: e.Value?.ToString())" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" value="@Email"
                       @onchange="e => Update(email: e.Value?.ToString())" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" value="@Phone"
                       @onchange="e => Update(phone: e.Value?.ToString())" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Name { get; set; } = "";
    [Parameter] public string Relationship { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<ReferenceData> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private async Task Update(string? name = null, string? relationship = null,
        string? email = null, string? phone = null)
    {
        var data = new ReferenceData(
            name ?? Name,
            relationship ?? Relationship,
            email ?? Email,
            phone ?? Phone
        );
        await OnChanged.InvokeAsync(data);
    }

    private async Task HandleRemove() => await OnRemove.InvokeAsync();

    public record ReferenceData(string Name, string Relationship, string Email, string Phone);
}

@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply

<nav class="mb-4">
    <div class="d-flex justify-content-between position-relative step-indicator">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <div class="text-center flex-fill step-item @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(!isCurrent && !isCompleted ? "dimmed" : "")"
                 role="@(isClickable ? "button" : "")"
                 @onclick="() => { if (isClickable) OnStepClicked.InvokeAsync(stepIndex); }">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                    @StepNames[stepIndex]
                </small>
            </div>
        }
    </div>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public List<string> StepNames { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

<style>
    .step-circle {
        width: 36px;
        height: 36px;
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
