    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@FullName"
               @onchange="e => { FullName = e.Value?.ToString() ?? ""; OnFieldChanged(); }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Email"
               @onchange="e => { Email = e.Value?.ToString() ?? ""; OnFieldChanged(); }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Phone"
               @onchange="e => { Phone = e.Value?.ToString() ?? ""; OnFieldChanged(); }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Address"
               @onchange="e => { Address = e.Value?.ToString() ?? ""; OnFieldChanged(); }" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }

    [Inject] private Services.IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private void OnFieldChanged()
    {
        ErrorMessage = null;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
        }
        finally
        {
            IsValidating = false;
        }
    }

    public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);
}

