@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <WorkEntryForm Index="@(index + 1)"
                   Company="@entry.Company"
                   Title="@entry.Title"
                   StartDate="@entry.StartDate"
                   EndDate="@entry.EndDate"
                   IsCurrent="@entry.IsCurrent"
                   Description="@entry.Description"
                   ShowRemove="@(Entries.Count > 1)"
                   OnChanged="data => HandleEntryChanged(index, data)"
                   OnRemove="() => HandleRemove(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="HandleBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback<List<WorkEntryModel>> OnBack { get; set; }

    private string? ErrorMessage;

    private void HandleEntryChanged(int index, WorkEntryForm.WorkEntryData data)
    {
        ErrorMessage = null;
        Entries[index] = new WorkEntryModel(data.Company, data.Title, data.StartDate, data.EndDate, data.IsCurrent, data.Description);
    }

    private void HandleRemove(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel("", "", null, null, false, ""));
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var e in Entries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate == null)
            {
                ErrorMessage = "Each position requires a company name, job title, and start date.";
                return;
            }
        }
        await OnNext.InvokeAsync(Entries);
    }

    private async Task HandleBack() => await OnBack.InvokeAsync(Entries);

    public record WorkEntryModel(string Company, string Title, DateTime? StartDate, DateTime? EndDate, bool IsCurrent, string Description);
}

