@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];

    <ReferenceForm Index="@(index + 1)"
                   Name="@r.Name"
                   Relationship="@r.Relationship"
                   Email="@r.Email"
                   Phone="@r.Phone"
                   ShowRemove="@(References.Count > 2)"
                   OnChanged="data => HandleChanged(index, data)"
                   OnRemove="() => HandleRemove(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="HandleBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceModel>> OnNext { get; set; }
    [Parameter] public EventCallback<List<ReferenceModel>> OnBack { get; set; }

    private string? ErrorMessage;

    private void HandleChanged(int index, ReferenceForm.ReferenceData data)
    {
        ErrorMessage = null;
        References[index] = new ReferenceModel(data.Name, data.Relationship, data.Email, data.Phone);
    }

    private void HandleRemove(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel("", "", "", ""));
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync(References);
    }

    private async Task HandleBack() => await OnBack.InvokeAsync(References);

    public record ReferenceModel(string Name, string Relationship, string Email, string Phone);
}

