@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              value="@CoverLetter"
              @oninput="HandleInput"
              placeholder="Write your cover letter here…"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="HandleBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback<string> OnBack { get; set; }

    private void HandleInput(ChangeEventArgs e)
    {
        CoverLetter = e.Value?.ToString() ?? "";
        if (CoverLetter.Length > MaxLength)
        {
            CoverLetter = CoverLetter[..MaxLength];
        }
    }

    private async Task HandleNext() => await OnNext.InvokeAsync(CoverLetter);
    private async Task HandleBack() => await OnBack.InvokeAsync(CoverLetter);
}

