+@page "/apply"
+@namespace sv_5a46dedb045442ba88966e9530f10eaa.Components.Pages.Apply
+@rendermode InteractiveServer
+@using sv_5a46dedb045442ba88966e9530f10eaa.Models
+
+<PageTitle>Job Application</PageTitle>
+
+<div class="container py-4" style="max-width: 800px;">
+    <h2 class="mb-4 text-center">Job Application</h2>
+
+    <StepIndicator CurrentStep="@_currentStep"
+                   CompletedSteps="@_completedSteps"
+                   StepNames="@_stepNames"
+                   OnStepClicked="GoToStep" />
+
+    @switch (_currentStep)
+    {
+        case 0:
+            <PersonalInfoStep FullName="@_fullName"
+                              Email="@_email"
+                              Phone="@_phone"
+                              Address="@_address"
+                              OnNext="HandlePersonalNext" />
+            break;
+
+        case 1:
+            <WorkHistoryStep Entries="@_workEntries"
+                             OnNext="HandleWorkNext"
+                             OnBack="HandleWorkBack" />
+            break;
+
+        case 2:
+            <ReferencesStep References="@_references"
+                            OnNext="HandleReferencesNext"
+                            OnBack="HandleReferencesBack" />
+            break;
+
+        case 3:
+            <CoverLetterStep CoverLetter="@_coverLetter"
+                             OnNext="HandleCoverLetterNext"
+                             OnBack="HandleCoverLetterBack" />
+            break;
+
+        case 4:
+            <ReviewStep Personal="@GetPersonalInfo()"
+                        WorkEntries="@_workEntries"
+                        References="@_references"
+                        CoverLetter="@_coverLetter"
+                        OnEditSection="GoToStep"
+                        OnBack="() => GoToStep(3)"
+                        OnSubmitted="HandleSubmitted" />
+            break;
+    }
+</div>
+
+@code {
+    private int _currentStep;
+    private readonly HashSet<int> _completedSteps = new();
+
+    private readonly List<string> _stepNames = new()
+    {
+        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
+    };
+
+    // Step 1 state
+    private string _fullName = "";
+    private string _email = "";
+    private string _phone = "";
+    private string _address = "";
+
+    // Step 2 state
+    private List<WorkHistoryStep.WorkEntryModel> _workEntries = new()
+    {
+        new("", "", null, null, false, "")
+    };
+
+    // Step 3 state
+    private List<ReferencesStep.ReferenceModel> _references = new()
+    {
+        new("", "", "", ""),
+        new("", "", "", "")
+    };
+
+    // Step 4 state
+    private string _coverLetter = "";
+
+    private PersonalInfo GetPersonalInfo() => new(_fullName, _email, _phone, _address);
+
+    private void GoToStep(int step)
+    {
+        if (_completedSteps.Contains(step) || step == _currentStep)
+        {
+            _currentStep = step;
+        }
+    }
+
+    // Step 1
+    private void HandlePersonalNext(PersonalInfoStep.PersonalInfoResult result)
+    {
+        _fullName = result.FullName;
+        _email = result.Email;
+        _phone = result.Phone;
+        _address = result.Address;
+        _completedSteps.Add(0);
+        _currentStep = 1;
+    }
+
+    // Step 2
+    private void HandleWorkNext(List<WorkHistoryStep.WorkEntryModel> entries)
+    {
+        _workEntries = entries;
+        _completedSteps.Add(1);
+        _currentStep = 2;
+    }
+
+    private void HandleWorkBack(List<WorkHistoryStep.WorkEntryModel> entries)
+    {
+        _workEntries = entries;
+        _currentStep = 0;
+    }
+
+    // Step 3
+    private void HandleReferencesNext(List<ReferencesStep.ReferenceModel> refs)
+    {
+        _references = refs;
+        _completedSteps.Add(2);
+        _currentStep = 3;
+    }
+
+    private void HandleReferencesBack(List<ReferencesStep.ReferenceModel> refs)
+    {
+        _references = refs;
+        _currentStep = 1;
+    }
+
+    // Step 4
+    private void HandleCoverLetterNext(string text)
+    {
+        _coverLetter = text;
+        _completedSteps.Add(3);
+        _currentStep = 4;
+    }
+
+    private void HandleCoverLetterBack(string text)
+    {
+        _coverLetter = text;
+        _currentStep = 2;
+    }
+
+    // Step 5
+    private void HandleSubmitted(int applicationId)
+    {
+        _completedSteps.Add(4);
+    }
+}
+

